Create application entry point with dependency wiring.

## Design
```go
// cmd/server/main.go

func main() {
    // 1. Load configuration
    cfg, err := config.Load()
    if err != nil {
        log.Fatal(err)
    }

    // 2. Setup logging
    logger, err := logging.NewLogger(&cfg.Logging)
    if err != nil {
        log.Fatal(err)
    }
    defer logger.Sync()

    // 3. Initialize SQLite session store
    store, err := session.NewSQLiteStore(cfg.Session.DatabasePath, logger)
    if err != nil {
        logger.Fatal("failed to create session store", zap.Error(err))
    }
    defer store.Close()

    // 4. Initialize session manager
    sessionMgr := session.NewManager(store, &cfg.Session, cfg.Kiro.SessionBasePath, logger)
    sessionMgr.Start() // Start cleanup goroutine
    defer sessionMgr.Stop()

    // 5. Create Slack client
    slackClient, err := slack.NewClient(
        cfg.Slack.BotToken, 
        cfg.Slack.AppToken, 
        cfg.Slack.DebugMode, 
        logger,
    )
    if err != nil {
        logger.Fatal("failed to create slack client", zap.Error(err))
    }

    // 6. Create Kiro bridge factory (with retry logic)
    kiroFactory := func(sessionDir string) kiro.Bridge {
        return kiro.NewRetryBridge(
            kiro.NewProcess(sessionDir, &cfg.Kiro, logger),
            cfg.Kiro.MaxRetries,
            logger,
        )
    }

    // 7. Create streaming factory
    streamFactory := func() streaming.Updater {
        return streaming.NewStreamer(slackClient, &cfg.Streaming, logger)
    }

    // 8. Create Slack handler
    handler := slack.NewHandler(slackClient, sessionMgr, kiroFactory, streamFactory, logger)

    // 9. Setup Socket Mode
    api := slacklib.New(cfg.Slack.BotToken, slacklib.OptionAppLevelToken(cfg.Slack.AppToken))
    socketClient := socketmode.New(api)
    handler.RegisterHandlers(socketClient)

    // 10. Handle shutdown gracefully
    ctx, cancel := context.WithCancel(context.Background())
    defer cancel()

    go func() {
        sigCh := make(chan os.Signal, 1)
        signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
        <-sigCh
        logger.Info("shutdown signal received")
        cancel()
    }()

    // 11. Run Socket Mode
    logger.Info("starting slack agent")
    if err := socketClient.RunContext(ctx); err != nil {
        logger.Fatal("socket mode error", zap.Error(err))
    }
}
```

## Retry Bridge Wrapper
```go
// internal/kiro/retry_bridge.go

type RetryBridge struct {
    bridge     Bridge
    maxRetries int
    logger     *zap.Logger
}

func (r *RetryBridge) SendMessage(ctx context.Context, msg string, handler ResponseHandler) error {
    var lastErr error
    for attempt := 0; attempt <= r.maxRetries; attempt++ {
        err := r.bridge.SendMessage(ctx, msg, handler)
        if err == nil {
            return nil
        }
        lastErr = err
        r.logger.Warn("kiro failed, retrying", 
            zap.Int("attempt", attempt+1),
            zap.Error(err))
    }
    return fmt.Errorf("kiro failed after %d retries: %w", r.maxRetries+1, lastErr)
}
```

