    ctx context.Context, 
    channelID, threadTS, userID string,
) (*Session, bool, error)

// Get retrieves a session by ID
func (m *Manager) Get(ctx context.Context, id SessionID) (*Session, error)

// UpdateActivity marks session as active (updates LastActivityAt)
func (m *Manager) UpdateActivity(ctx context.Context, id SessionID) error

// Close terminates a session and cleans up resources
// - Closes Kiro bridge if exists
// - Optionally removes session directory
// - Removes from store
func (m *Manager) Close(ctx context.Context, id SessionID) error

// Cleanup removes stale sessions (runs periodically)
// - Find sessions with LastActivityAt < now - IdleTimeout
// - Skip sessions with status = Processing
// - Close each stale session
func (m *Manager) Cleanup(ctx context.Context) error

// Start begins the cleanup goroutine
func (m *Manager) Start()

// Stop halts the cleanup goroutine
func (m *Manager) Stop()
```

## Cleanup Strategy
- Run every 5 minutes via ticker
- Query for idle sessions (LastActivityAt + IdleTimeout < now)
- Skip sessions currently processing
- Close each idle session (terminates Kiro, removes dir)

