func TestE2E_BotRespondsToMention(t *testing.T) {
    if os.Getenv("E2E_TEST") != "true" {
        t.Skip("E2E tests disabled")
    }

    api := slack.New(os.Getenv("SLACK_BOT_TOKEN"))
    testChannel := os.Getenv("TEST_CHANNEL_ID")
    botUserID := os.Getenv("BOT_USER_ID")

    // Post mention
    _, ts, err := api.PostMessage(testChannel,
        slack.MsgOptionText(fmt.Sprintf("<@%s> Hello, what is 2+2?", botUserID), false))
    require.NoError(t, err)

    // Wait for response
    time.Sleep(30 * time.Second)

    // Fetch thread replies
    replies, _, _, err := api.GetConversationReplies(&slack.GetConversationRepliesParameters{
        ChannelID: testChannel,
        Timestamp: ts,
    })
    require.NoError(t, err)

    // Verify bot replied
    var botReply *slack.Message
    for _, r := range replies {
        if r.User == botUserID && r.Timestamp != ts {
            botReply = &r
            break
        }
    }

    require.NotNil(t, botReply, "Bot should have replied")
    assert.NotEmpty(t, botReply.Text)
}

